import { describe, expect, it } from "vitest";
import { priceOrder } from "../src/pricing.js";

// Behavior under test (from src/pricing.js):
//   priceOrder(lines, coupon?) -> { subtotalCents, discountCents, totalCents }
//   - subtotalCents = sum of unitCents * qty ([] -> all zeros)
//   - qty must be a positive integer, else RangeError
//   - tier discount: 10% of subtotal (rounded, .5 up) when subtotal >= 10000
//   - coupon discount: capped-pct (max 30) of the subtotal AFTER the tier
//     discount, rounded (.5 up)
//   - discountCents = tier + coupon; totalCents = subtotal - discount

describe("priceOrder", () => {
  describe("subtotal", () => {
    it("returns all zeros for an empty order", () => {
      expect(priceOrder([])).toEqual({
        subtotalCents: 0,
        discountCents: 0,
        totalCents: 0,
      });
    });

    it("computes subtotal for a single line as unitCents * qty", () => {
      expect(priceOrder([{ unitCents: 250, qty: 3 }]).subtotalCents).toBe(750);
    });

    it("sums unitCents * qty across multiple lines", () => {
      const result = priceOrder([
        { unitCents: 100, qty: 3 },
        { unitCents: 200, qty: 1 },
      ]);
      expect(result.subtotalCents).toBe(500);
    });

    it("treats a zero unit price as a zero-cost line", () => {
      expect(priceOrder([{ unitCents: 0, qty: 5 }])).toEqual({
        subtotalCents: 0,
        discountCents: 0,
        totalCents: 0,
      });
    });

    it("handles a quantity of one", () => {
      expect(priceOrder([{ unitCents: 4200, qty: 1 }]).subtotalCents).toBe(4200);
    });
  });

  describe("qty validation", () => {
    it("throws RangeError for a quantity of zero", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: 0 }])).toThrow(RangeError);
    });

    it("throws RangeError for a negative quantity", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: -1 }])).toThrow(RangeError);
    });

    it("throws RangeError for a non-integer (fractional) quantity", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: 1.5 }])).toThrow(RangeError);
    });

    it("throws RangeError for a NaN quantity", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: NaN }])).toThrow(RangeError);
    });

    it("throws RangeError for a non-numeric quantity", () => {
      expect(() => priceOrder([{ unitCents: 100, qty: "2" }])).toThrow(RangeError);
    });

    it("throws when any line has an invalid quantity, even if earlier lines are valid", () => {
      expect(() =>
        priceOrder([
          { unitCents: 100, qty: 2 },
          { unitCents: 100, qty: 0 },
        ]),
      ).toThrow(RangeError);
    });

    it("accepts an integer-valued quantity written as a float (2.0)", () => {
      expect(priceOrder([{ unitCents: 100, qty: 2.0 }]).subtotalCents).toBe(200);
    });
  });

  describe("tier discount", () => {
    it("applies no tier discount below the 10000 threshold", () => {
      const result = priceOrder([{ unitCents: 9999, qty: 1 }]);
      expect(result.discountCents).toBe(0);
      expect(result.totalCents).toBe(9999);
    });

    it("applies a 10% tier discount exactly at the 10000 threshold", () => {
      expect(priceOrder([{ unitCents: 10000, qty: 1 }])).toEqual({
        subtotalCents: 10000,
        discountCents: 1000,
        totalCents: 9000,
      });
    });

    it("applies a 10% tier discount above the threshold", () => {
      expect(priceOrder([{ unitCents: 2500, qty: 4 }])).toEqual({
        subtotalCents: 10000,
        discountCents: 1000,
        totalCents: 9000,
      });
    });

    it("reaches the threshold via multiple lines", () => {
      const result = priceOrder([
        { unitCents: 6000, qty: 1 },
        { unitCents: 2000, qty: 2 },
      ]);
      expect(result.subtotalCents).toBe(10000);
      expect(result.discountCents).toBe(1000);
    });

    it("rounds the tier discount to the nearest cent with .5 rounding up", () => {
      // 12345 * 0.1 = 1234.5 -> 1235
      const result = priceOrder([{ unitCents: 12345, qty: 1 }]);
      expect(result.subtotalCents).toBe(12345);
      expect(result.discountCents).toBe(1235);
      expect(result.totalCents).toBe(11110);
    });
  });

  describe("coupon discount", () => {
    it("applies no coupon discount when no coupon is provided", () => {
      expect(priceOrder([{ unitCents: 2500, qty: 4 }])).toEqual({
        subtotalCents: 10000,
        discountCents: 1000,
        totalCents: 9000,
      });
    });

    it("applies no coupon discount for a 0% coupon", () => {
      expect(priceOrder([{ unitCents: 2500, qty: 4 }], { pct: 0 })).toEqual({
        subtotalCents: 10000,
        discountCents: 1000,
        totalCents: 9000,
      });
    });

    it("applies a coupon percentage below the tier threshold (no tier discount)", () => {
      // subtotal 1000, no tier, 20% coupon -> 200
      expect(priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 20 })).toEqual({
        subtotalCents: 1000,
        discountCents: 200,
        totalCents: 800,
      });
    });

    it("computes the coupon on the subtotal AFTER the tier discount", () => {
      // subtotal 10000, tier 1000, after-tier 9000, 30% coupon -> 2700
      // (a coupon on the full subtotal would instead give 3000)
      expect(priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 30 })).toEqual({
        subtotalCents: 10000,
        discountCents: 3700,
        totalCents: 6300,
      });
    });

    it("caps coupon percentages above 30 at 30", () => {
      // pct 50 is capped to 30: subtotal 10000, tier 1000, after 9000 -> 2700
      expect(priceOrder([{ unitCents: 5000, qty: 2 }], { pct: 50 })).toEqual({
        subtotalCents: 10000,
        discountCents: 3700,
        totalCents: 6300,
      });
    });

    it("treats a percentage just above the cap the same as 30", () => {
      const capped = priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 31 });
      const atCap = priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 30 });
      expect(capped).toEqual(atCap);
      expect(capped.discountCents).toBe(300); // 1000 * 30%
    });

    it("caps a 100% coupon at 30%", () => {
      // subtotal 9999 (no tier), 100% -> capped 30% -> round(9999*0.3)=3000
      expect(priceOrder([{ unitCents: 9999, qty: 1 }], { pct: 100 })).toEqual({
        subtotalCents: 9999,
        discountCents: 3000,
        totalCents: 6999,
      });
    });

    it("does not cap a percentage of exactly 30", () => {
      // subtotal 1000, no tier, 30% -> 300
      expect(priceOrder([{ unitCents: 1000, qty: 1 }], { pct: 30 }).discountCents).toBe(300);
    });

    it("rounds the coupon discount to the nearest cent with .5 rounding up", () => {
      // subtotal 9995 (no tier), 30% -> 9995 * 0.3 = 2998.5 -> 2999
      expect(priceOrder([{ unitCents: 9995, qty: 1 }], { pct: 30 })).toEqual({
        subtotalCents: 9995,
        discountCents: 2999,
        totalCents: 6996,
      });
    });
  });

  describe("combined discounts and totals", () => {
    it("stacks tier and coupon discounts through the full pipeline", () => {
      // subtotal 12345, tier round(1234.5)=1235, after 11110,
      // coupon round(11110*0.3)=3333, discount 4568, total 7777
      expect(priceOrder([{ unitCents: 12345, qty: 1 }], { pct: 30 })).toEqual({
        subtotalCents: 12345,
        discountCents: 4568,
        totalCents: 7777,
      });
    });

    it("always satisfies discountCents = tier + coupon and total = subtotal - discount", () => {
      const result = priceOrder([{ unitCents: 12345, qty: 1 }], { pct: 30 });
      expect(result.discountCents).toBe(1235 + 3333);
      expect(result.totalCents).toBe(result.subtotalCents - result.discountCents);
    });

    it("returns exactly the three documented keys", () => {
      expect(Object.keys(priceOrder([{ unitCents: 500, qty: 1 }])).sort()).toEqual(
        ["discountCents", "subtotalCents", "totalCents"],
      );
    });

    it("applies a coupon on an empty order without error", () => {
      expect(priceOrder([], { pct: 30 })).toEqual({
        subtotalCents: 0,
        discountCents: 0,
        totalCents: 0,
      });
    });
  });
});

